module HMAC (  
    input wire clk,  
    input wire reset,  
    input wire [7:0] key,  
    input wire [7:0] message,  
    output reg [7:0] mac  
);  
    reg [7:0] obf_combined;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            mac <= 8'b0;  
            obf_combined <= 8'b0;  
        end else begin  
            obf_combined <= key ^ message; // Simple XOR operation as the hash function  
            mac <= obf_combined;  
        end  
    end  
endmodule
